from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when a product price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a product quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item is not found in the cart."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in the shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Defines the interface for cart discounts."""

    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Apply the discount to a subtotal and return the discounted total."""


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Apply the percentage discount to the provided subtotal."""
        discount_amount = subtotal * (self.percentage / Decimal("100"))
        return max(Decimal("0"), subtotal - discount_amount)


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Apply the flat discount to the provided subtotal."""
        return max(Decimal("0"), subtotal - self.amount)


class ShoppingCart:
    """Manages cart items, discounts, and total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(self, product_name: str, unit_price: Decimal, quantity: int) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_product_name = self._validate_product_name(product_name)
        self._validate_unit_price(unit_price)
        self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_product_name)

        if existing_item is None:
            self._items[normalized_product_name] = CartItem(
                product_name=normalized_product_name,
                unit_price=unit_price,
                quantity=quantity,
            )
            return

        if existing_item.unit_price != unit_price:
            raise InvalidPriceError(
                f"Product '{normalized_product_name}' already exists with unit price "
                f"{existing_item.unit_price}; received {unit_price}."
            )

        self._items[normalized_product_name] = replace(
            existing_item,
            quantity=existing_item.quantity + quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_product_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_product_name)

        del self._items[normalized_product_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_product_name = self._validate_product_name(product_name)
        self._validate_quantity(quantity)

        existing_item = self._get_existing_item(normalized_product_name)
        self._items[normalized_product_name] = replace(existing_item, quantity=quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum(
            (item.total_price for item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount to the cart."""
        self._validate_percentage_discount(percentage)
        self._discount = PercentageDiscount(percentage=percentage)

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat discount to the cart."""
        self._validate_flat_discount(amount)
        self._discount = FlatDiscount(amount=amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        return self._discount.apply_to(subtotal)

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all cart items with their details."""
        return tuple(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise ItemNotFoundError(f"Product '{product_name}' is not in the cart.")

        return self._items[product_name]

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        normalized_product_name = product_name.strip()

        if not normalized_product_name:
            raise InvalidProductNameError("Product name must not be empty.")

        return normalized_product_name

    @staticmethod
    def _validate_unit_price(unit_price: Decimal) -> None:
        if unit_price < Decimal("0"):
            raise InvalidPriceError("Unit price must be greater than or equal to 0.")

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than 0.")

    @staticmethod
    def _validate_percentage_discount(percentage: Decimal) -> None:
        if percentage < Decimal("0") or percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

    @staticmethod
    def _validate_flat_discount(amount: Decimal) -> None:
        if amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount must be greater than or equal to 0.")
